// --- Import/Export Logic ---
function handleExportSchedules() {
    if (state.allSchedules.length === 0) {
        console.warn("No schedules to export.");
        return;
    }
    const schedulesToExport = state.allSchedules.map(s => ({
        name: s.name,
        bells: s.bells
    }));
    const data = {
        appId: state.appId,
        exportedAt: new Date().toISOString(),
        schedules: schedulesToExport
    };
    const jsonString = JSON.stringify(data, null, 2);
    const blob = new Blob([jsonString], { type: 'application/json' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `school-bell-schedules-${new Date().toISOString().split('T')[0]}.json`;
    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);
    URL.revokeObjectURL(url);
}

